INSERT INTO "activities" ("id", "day_id", "time", "location", "duration", "cost", "maps_query", "website_link", "parking", "notes", "ticket_file_name", "ticket_file_data", "date", "created_by_email") VALUES ('act-1-2', 'day-1', '15:00', 'Praça Jemaa el-Fnaa', '3h', 'Gratuito', 'Jemaa el-Fnaa, Marrakech', '', '', 'Explore o coração pulsante de Marrakech. Veja os encantadores de serpentes, músicos e aproveite para tomar um suco de laranja fresco nas barracas tradicionais.', '', '', '', NULL);
INSERT INTO "activities" ("id", "day_id", "time", "location", "duration", "cost", "maps_query", "website_link", "parking", "notes", "ticket_file_name", "ticket_file_data", "date", "created_by_email") VALUES ('act-1-3', 'day-1', '20:00', 'Restaurante Dar Moha', '2h', 'R$ 280', 'Dar Moha, Marrakech', '', '', 'Jantar romântico ao redor de uma piscina iluminada em um antigo palácio, servindo a alta gastronomia marroquina com um toque moderno.', '', '', '', NULL);
INSERT INTO "activities" ("id", "day_id", "time", "location", "duration", "cost", "maps_query", "website_link", "parking", "notes", "ticket_file_name", "ticket_file_data", "date", "created_by_email") VALUES ('act-1-1', 'day-1', '11:00', 'Aeroporto de Marrakech-Menara', '1h30', 'Gratuito', 'Marrakech-Menara Airport, Marrakech', '', '', 'Retirada do carro alugado diretamente no aeroporto. Lembre-se de contratar seguro total para as estradas marroquinas.', '', '', '', NULL);
INSERT INTO "activities" ("id", "day_id", "time", "location", "duration", "cost", "maps_query", "website_link", "parking", "notes", "ticket_file_name", "ticket_file_data", "date", "created_by_email") VALUES ('act-2-1', 'day-2', '08:30', 'Passo de Montanha Tizi n''Tichka', '4h', 'Gratuito', 'Tizi n''Tichka, Morocco', '', '', 'Dirija com cuidado por uma das estradas mais cênicas do mundo, cruzando a Cordilheira do Atlas a 2.260 metros de altitude.', '', '', '', NULL);
INSERT INTO "activities" ("id", "day_id", "time", "location", "duration", "cost", "maps_query", "website_link", "parking", "notes", "ticket_file_name", "ticket_file_data", "date", "created_by_email") VALUES ('act-2-2', 'day-2', '13:00', 'Ksar de Ait Benhaddou', '2h30', 'R$ 30', 'Aït Benhaddou, Morocco', '', '', 'Patrimônio Mundial da UNESCO. Uma fortaleza de argila impressionante onde foram filmados Gladiador e Game of Thrones. Contrate um guia local na entrada.', '', '', '', NULL);
INSERT INTO "activities" ("id", "day_id", "time", "location", "duration", "cost", "maps_query", "website_link", "parking", "notes", "ticket_file_name", "ticket_file_data", "date", "created_by_email") VALUES ('act-2-3', 'day-2', '16:30', 'Atlas Film Studios', '1h30', 'R$ 45', 'Atlas Corporation Studios, Ouarzazate', '', '', 'Visite os cenários monumentais de grandes produções do cinema mundial no meio do deserto rochoso.', '', '', '', NULL);
INSERT INTO "activities" ("id", "day_id", "time", "location", "duration", "cost", "maps_query", "website_link", "parking", "notes", "ticket_file_name", "ticket_file_data", "date", "created_by_email") VALUES ('act-3-1', 'day-3', '09:00', 'Gargantas do Todra', '4h30', 'Gratuito', 'Todgha Gorge, Morocco', '', '', 'Parada estratégica na viagem para Merzouga para caminhar entre os imensos desfiladeiros de rocha calcária que chegam a 300 metros de altura.', '', '', '', NULL);
INSERT INTO "activities" ("id", "day_id", "time", "location", "duration", "cost", "maps_query", "website_link", "parking", "notes", "ticket_file_name", "ticket_file_data", "date", "created_by_email") VALUES ('act-3-2', 'day-3', '17:00', 'Dunas de Erg Chebbi', '2h', 'R$ 250', 'Erg Chebbi, Merzouga', '', '', 'Deixe o carro no ponto de encontro combinado com o acampamento e faça um passeio de camelo ao pôr do sol em direção às dunas gigantes.', '', '', '', NULL);
INSERT INTO "activities" ("id", "day_id", "time", "location", "duration", "cost", "maps_query", "website_link", "parking", "notes", "ticket_file_name", "ticket_file_data", "date", "created_by_email") VALUES ('act-3-3', 'day-3', '20:30', 'Jantar sob as Estrelas', '3h', 'Incluso', 'Merzouga Luxury Desert Camp', '', '', 'Jantar tradicional berbere ao redor da fogueira com música Gnawa ao vivo e observação do céu estrelado do Saara.', '', '', '', NULL);
INSERT INTO "activities" ("id", "day_id", "time", "location", "duration", "cost", "maps_query", "website_link", "parking", "notes", "ticket_file_name", "ticket_file_data", "date", "created_by_email") VALUES ('act-4-1', 'day-4', '09:00', 'Vale do Ziz', '3h', 'Gratuito', 'Ziz Valley, Morocco', '', '', 'Dirija admirando o contraste surreal entre o deserto árido e o imenso oásis verdejante repleto de tamareiras.', '', '', '', NULL);
INSERT INTO "activities" ("id", "day_id", "time", "location", "duration", "cost", "maps_query", "website_link", "parking", "notes", "ticket_file_name", "ticket_file_data", "date", "created_by_email") VALUES ('act-4-2', 'day-4', '15:00', 'Midelt - Centro Histórico', '2h', 'Gratuito', 'Midelt, Morocco', '', '', 'Caminhada tranquila pela capital das maçãs do Marrocos, apreciando a vista deslumbrante das montanhas Ayachi cobertas de neve.', '', '', '', NULL);
INSERT INTO "activities" ("id", "day_id", "time", "location", "duration", "cost", "maps_query", "website_link", "parking", "notes", "ticket_file_name", "ticket_file_data", "date", "created_by_email") VALUES ('act-5-2', 'day-5', '15:00', 'Check-in e Chá da Tarde no Riad Fès', '1h30', 'Gratuito', 'Riad Fès, Fez', '', '', 'Aproveite para relaxar e tomar o tradicional chá de menta marroquino no pátio interno do hotel.', '', '', '', NULL);
INSERT INTO "activities" ("id", "day_id", "time", "location", "duration", "cost", "maps_query", "website_link", "parking", "notes", "ticket_file_name", "ticket_file_data", "date", "created_by_email") VALUES ('act-5-1', 'day-5', '09:30', 'Floresta de Cedros de Azrou', '2h', 'Gratuito', 'Cèdre Gouraud Forest, Azrou', '', '', 'Parada charmosa para ver e alimentar os macacos-da-barbária que habitam os bosques de cedros milenares.', '', '', '', NULL);
INSERT INTO "activities" ("id", "day_id", "time", "location", "duration", "cost", "maps_query", "website_link", "parking", "notes", "ticket_file_name", "ticket_file_data", "date", "created_by_email") VALUES ('act-6-1', 'day-6', '09:00', 'Fez el Bali (Medina)', '4h', 'R$ 150', 'Fes El Bali, Fez', '', '', 'Tour privado com guia credenciado pelo labirinto de mais de 9.000 ruelas medievais. Visita à Universidade Al-Qarawiyyin.', '', '', '', NULL);
INSERT INTO "activities" ("id", "day_id", "time", "location", "duration", "cost", "maps_query", "website_link", "parking", "notes", "ticket_file_name", "ticket_file_data", "date", "created_by_email") VALUES ('act-6-2', 'day-6', '14:00', 'Curtume Chouara', '1h', 'Gratuito', 'Chouara Tannery, Fez', '', '', 'Observe os tanques de tintura de couro coloridos de um terraço panorâmico. Oferecem um ramo de hortelã para amenizar o cheiro forte.', '', '', '', NULL);
INSERT INTO "activities" ("id", "day_id", "time", "location", "duration", "cost", "maps_query", "website_link", "parking", "notes", "ticket_file_name", "ticket_file_data", "date", "created_by_email") VALUES ('act-6-3', 'day-6', '19:30', 'Jantar no L''Amandier Palais Faraj', '2h', 'R$ 320', 'Palais Faraj Suites & Spa, Fez', '', '', 'Jantar sofisticado com vista deslumbrante para a medina iluminada à noite.', '', '', '', NULL);
INSERT INTO "activities" ("id", "day_id", "time", "location", "duration", "cost", "maps_query", "website_link", "parking", "notes", "ticket_file_name", "ticket_file_data", "date", "created_by_email") VALUES ('act-7-1', 'day-7', '08:30', 'Viagem de Fez para Casablanca', '3h30', 'Gratuito', 'Casablanca, Morocco', '', '', 'Trajeto tranquilo feito pela excelente rodovia pedagiada (Auto-estrada A2).', '', '', '', NULL);
INSERT INTO "activities" ("id", "day_id", "time", "location", "duration", "cost", "maps_query", "website_link", "parking", "notes", "ticket_file_name", "ticket_file_data", "date", "created_by_email") VALUES ('act-7-2', 'day-7', '14:30', 'Mesquita Hassan II', '2h', 'R$ 130', 'Hassan II Mosque, Casablanca', '', '', 'Uma das poucas mesquitas ativas que permite a entrada de não-muçulmanos. Erguida sobre o Oceano Atlântico, possui o segundo maior minarete do mundo.', '', '', '', NULL);
INSERT INTO "activities" ("id", "day_id", "time", "location", "duration", "cost", "maps_query", "website_link", "parking", "notes", "ticket_file_name", "ticket_file_data", "date", "created_by_email") VALUES ('act-7-3', 'day-7', '20:00', 'Rick''s Café', '2h30', 'R$ 290', 'Rick''s Café, Casablanca', '', '', 'Réplica perfeita do bar lendário do clássico filme ''Casablanca'' de 1942. Reserva obrigatória com semanas de antecedência.', '', '', '', NULL);
INSERT INTO "activities" ("id", "day_id", "time", "location", "duration", "cost", "maps_query", "website_link", "parking", "notes", "ticket_file_name", "ticket_file_data", "date", "created_by_email") VALUES ('act-8-1', 'day-8', '09:00', 'Viagem de Casablanca a Marrakech', '2h30', 'Gratuito', 'Marrakech, Morocco', '', '', 'Auto-estrada direta e rápida ligando as duas principais cidades.', '', '', '', NULL);
INSERT INTO "activities" ("id", "day_id", "time", "location", "duration", "cost", "maps_query", "website_link", "parking", "notes", "ticket_file_name", "ticket_file_data", "date", "created_by_email") VALUES ('act-8-2', 'day-8', '15:00', 'Jardim Majorelle e Museu YSL', '2h30', 'R$ 110', 'Jardin Majorelle, Marrakech', '', '', 'Visite o icônico jardim azul-cobalto que pertenceu a Yves Saint Laurent, seguido pelo museu adjacente dedicado ao estilista.', '', '', '', NULL);
INSERT INTO "activities" ("id", "day_id", "time", "location", "duration", "cost", "maps_query", "website_link", "parking", "notes", "ticket_file_name", "ticket_file_data", "date", "created_by_email") VALUES ('act-9-1', 'day-9', '09:30', 'Palácio da Bahia', '1h30', 'R$ 40', 'Bahia Palace, Marrakech', '', '', 'Uma obra-prima da arquitetura marroquina do século XIX, com pátios deslumbrantes revestidos de azulejos zellij.', '', '', '', NULL);
INSERT INTO "activities" ("id", "day_id", "time", "location", "duration", "cost", "maps_query", "website_link", "parking", "notes", "ticket_file_name", "ticket_file_data", "date", "created_by_email") VALUES ('act-9-2', 'day-9', '15:00', 'Hammam Tradicional no Les Bains de Marrakech', '2h', 'R$ 380', 'Les Bains de Marrakech, Marrakech', '', '', 'Momento de puro relaxamento a dois com banho turco tradicional, esfoliação com sabão negro e massagem com óleo de argan.', '', '', '', NULL);
INSERT INTO "activities" ("id", "day_id", "time", "location", "duration", "cost", "maps_query", "website_link", "parking", "notes", "ticket_file_name", "ticket_file_data", "date", "created_by_email") VALUES ('act-10-1', 'day-10', '09:00', 'Souks de Marrakech', '3h', 'Gratuito', 'Souks of Marrakech, Marrakech', '', '', 'Últimas compras de tapetes, luminárias e especiarias. Lembre-se que negociar o preço faz parte da cultura local!', '', '', '', NULL);
INSERT INTO "activities" ("id", "day_id", "time", "location", "duration", "cost", "maps_query", "website_link", "parking", "notes", "ticket_file_name", "ticket_file_data", "date", "created_by_email") VALUES ('act-10-2', 'day-10', '13:00', 'Devolução do Carro no Aeroporto', '1h', 'Gratuito', 'Marrakech-Menara Airport, Marrakech', '', '', 'Entrega do veículo alugado com tanque cheio antes de prosseguir para o portão de embarque.', '', '', '', NULL);
