INSERT INTO "general_tips" ("id", "itinerary_id", "category", "title", "content") VALUES ('tip-1', 48, 'Transporte', 'Dirigindo no Marrocos', 'As estradas principais e rodovias são excelentes e bem sinalizadas. No entanto, respeite estritamente os limites de velocidade, pois há radares móveis frequentes da polícia rodoviária em todas as entradas de cidades.');
INSERT INTO "general_tips" ("id", "itinerary_id", "category", "title", "content") VALUES ('tip-2', 48, 'Cultura', 'Vestimentas e Costumes', 'Para visitar mesquitas e caminhar pelas medinas, vista-se de maneira respeitosa (ombros e joelhos cobertos). É recomendável que a esposa leve um lenço leve na bolsa para o caso de necessidade de cobrir a cabeça.');
INSERT INTO "general_tips" ("id", "itinerary_id", "category", "title", "content") VALUES ('tip-3', 48, 'Financeiro', 'Dinheiro e Gorjetas (Baksheesh)', 'A moeda local é o Dirham Marroquino (MAD). Tenha sempre dinheiro em espécie para pedágios, estacionamentos e gorjetas, que são culturalmente esperadas por quase todos os serviços prestados.');
