INSERT INTO "general_tips" ("id", "itinerary_id", "category", "title", "content") VALUES ('tip_ny_walking-0dftkd-vmxqg-vt6e2s-4cmfr9-3fbw0c-672xwc-ahpdd6-f3a0rv-ty490p-q9lueec-x7cuv-gqdj6x-l1tsud-hmxyh', 45, 'Nova York', '🥾 Logística Urbana: Use Tênis Confortáveis', 'Nova York é uma cidade projetada para se caminhar! É muito comum andar de **12km a 20km por dia** entre atrações e estações de metrô. 
