INSERT INTO "general_tips" ("id", "itinerary_id", "category", "title", "content") VALUES ('tip_ny_safety-r16s4n-ik7wt-wot5pf-pb81q3-0kuaj-pmfjow-u9igsm-71uvsv-6mzjim-w2zn1f-ymljt-m2ccvc-swamxr-5ig0j6', 45, 'Nova York', '⚠️ Segurança e Cuidado com Pertences', 'Nova York é geralmente muito segura, mas em áreas turísticas superlotadas como a Times Square, grandes museus e dentro do metrô, bolsistas e batedores de carteira atuam.
INSERT INTO "general_tips" ("id", "itinerary_id", "category", "title", "content") VALUES ('tip3-ioh6i-i66zjb-buynm7-3oxar-t655be-4rlkn-7ss6ug-0mj3y-iy2kf-yqlyt-dxxcg-5ubya8-k16l1-aneqlm', 45, 'Geral', 'Diretrizes sobre Chip de Internet e Roaming', 'Lembre-se de ativar o chip internacional eSIM antes de desembarcar em Washington (IAD) para garantir comunicação instantânea com o grupo de viajantes através do aplicativo.');
INSERT INTO "general_tips" ("id", "itinerary_id", "category", "title", "content") VALUES ('tip1-k9h6ae-mvs8r-bzhs2e-2cb7rd-n781k-hmddtn-eu7w9b-948he6-mpm83-08fqa-9z95b-t4k2ob-8fvvmo-ymxl5c', 45, 'Nova York', 'Classificação Sanitária de Restaurantes', '**Nota A:** É a melhor classificação possível. Significa que o restaurante teve pouquíssimas ou nenhuma violação sanitária durante a inspeção. A grande maioria dos restaurantes da cidade possui essa nota.
